function _loadActiveBots() {
    try {
        if (fs.existsSync(JADIBOT_PERSIST_FILE)) {
            return JSON.parse(fs.readFileSync(JADIBOT_PERSIST_FILE, 'utf8'))
        }
    } catch(e) {}
    return {}
}

function _saveActiveBots() {
    const data = {}
    for (const [nomor, info] of Object.entries(_childBots)) {
        data[nomor] = { nomor, ownerJid: info.ownerJid, startTime: info.startTime }
    }
    try { fs.writeFileSync(JADIBOT_PERSIST_FILE, JSON.stringify(data, null, 2)) } catch(e) {}
}

// Fungsi spawn bot baru sebagai child process
// msgCallback dipasang LANGSUNG ke child sebelum return ‚Äî eliminasi race condition IPC
function _spawnChildBot(nomor, ownerJid, msgCallback, _freshStart = false) {
    if (_childBots[nomor]) return { ok: false, reason: 'already_running' }
    const sessionDir = `./sessions/${nomor}`
    if (_freshStart && fs.existsSync(sessionDir)) {
        try { fs.rmSync(sessionDir, { recursive: true, force: true }) } catch(e) {}
    }
    if (!fs.existsSync(sessionDir)) fs.mkdirSync(sessionDir, { recursive: true })
    // Clone saluran_config.json & bot_config.json (menuImage) dari parent ke child
    try {
        const _cDst1 = `${sessionDir}/saluran_config.json`
        if (fs.existsSync('./saluran_config.json')) {
            fs.copyFileSync('./saluran_config.json', _cDst1)
        } else {
            fs.writeFileSync(_cDst1, JSON.stringify({ link: 'https://whatsapp.com/channel/0029Vb846mn8aKvFGz7zg033' }, null, 2))
        }
        const _cDst2 = `${sessionDir}/bot_config.json`
        let _pBotCfg = {}
        try { _pBotCfg = JSON.parse(fs.readFileSync('./bot_config.json', 'utf8')) } catch(e) {}
        let _cBotCfg = {}
        try { _cBotCfg = JSON.parse(fs.readFileSync(_cDst2, 'utf8')) } catch(e) {}
        if (_pBotCfg.menuImage !== undefined)   _cBotCfg.menuImage   = _pBotCfg.menuImage
        if (_pBotCfg.menuIsVideo !== undefined)  _cBotCfg.menuIsVideo = _pBotCfg.menuIsVideo
        fs.writeFileSync(_cDst2, JSON.stringify(_cBotCfg, null, 2))
    } catch(e) { console.log('[JADIBOT] Gagal clone config:', e.message) }

    const child = require('child_process').fork(__filename, [], {
        env: {
            ...process.env,
            JADIBOT_CHILD: '1',
            JADIBOT_NOMOR: nomor,
            JADIBOT_SESSION: sessionDir,
            JADIBOT_OWNER_JID: ownerJid,
            JADIBOT_CONFIG_DIR: sessionDir
        },
        silent: true,
        detached: false
    })
    child.stdout?.on('data', d => console.log(`[NEXUS:${nomor}] ${d.toString().trim()}`))
    child.stderr?.on('data', d => console.log(`[NEXUS:${nomor}:ERR] ${d.toString().trim()}`))
    // Pasang IPC listener SEKARANG sebelum child sempat kirim pesan apapun
    if (msgCallback) child.on('message', msgCallback)
    child.on('exit', (code) => {
        console.log(`[NEXUS:${nomor}] Process exit (${code})`)
        // Hapus listener supaya tidak memory leak
        if (msgCallback) child.removeListener('message', msgCallback)
        delete _childBots[nomor]
        _saveActiveBots()
    })
    _childBots[nomor] = { process: child, pid: child.pid, startTime: Date.now(), ownerJid }
    _saveActiveBots()
    return { ok: true, pid: child.pid }
}

// ‚ïê‚ïê INJECT STICKER METADATA (packname & author ke file .webp) ‚ïê‚ïê
// Cara yang benar: buat EXIF buffer dengan format yang WhatsApp baca
function buildExifBuffer(packname, author) {
    const json = JSON.stringify({
        'sticker-pack-name': packname,
        'sticker-pack-publisher': author,
        'emojis': ['üé®']
    })
    const utf8 = Buffer.from(json, 'utf-8')
    // Format: 6 byte header Exif + payload JSON
    const exif = Buffer.alloc(utf8.length + 6)
    exif.write('Exif\x00\x00', 0, 'latin1')
    utf8.copy(exif, 6)
    return exif
}

async function addStickerMeta(webpBuf, packname, author) {
    try {
        const img = new webpmux.Image()
        await img.load(webpBuf)
        img.exif = buildExifBuffer(packname, author)
        return await img.save(null) // return Buffer, tidak tulis ke file
    } catch(e) {
        // Kalau gagal, kembalikan buffer asli tanpa metadata
        return webpBuf
    }
}

