const _DEDUP_WINDOW = 30 * 60 * 1000  // 30 menit

// Load dari file saat startup
try {
    if (require('fs').existsSync(_DEDUP_FILE)) {
        const _raw = JSON.parse(require('fs').readFileSync(_DEDUP_FILE, 'utf8'))
        const _cutoff = Date.now() - _DEDUP_WINDOW
        let _loaded = 0
        for (const [k, v] of Object.entries(_raw)) {
            if (v > _cutoff) { _processedMsgIds.set(k, v); _loaded++ }
        }
        console.log(`[DEDUP] Loaded ${_loaded} recent msg IDs from file`)
    }
} catch(e) { console.log('[DEDUP] Could not load dedup file:', e.message) }

// Simpan ke file setiap 60 detik
setInterval(() => {
    try {
        const _cutoff = Date.now() - _DEDUP_WINDOW
        const _obj = {}
        for (const [k, v] of _processedMsgIds.entries()) {
            if (v > _cutoff) _obj[k] = v
        }
        require('fs').writeFileSync(_DEDUP_FILE, JSON.stringify(_obj))
    } catch(e) {}
}, 60000)

