// ‚ïê‚ïê Memori AI dihapus ‚Äî bot tidak menyimpan riwayat percakapan ‚ïê‚ïê

async function askAI(query, userId) {
    const finalQuery = _buildQuery(query)

    // ‚îÄ‚îÄ Gemini API saja ‚Äî 100% dari .sapikey yang di-set owner ‚îÄ‚îÄ
    // Coba semua key yang tersimpan, auto-rotate kalau satu key error/limit
    const _validKeys = _geminiKeys.filter(k => k && k.length > 10)
    if (_validKeys.length === 0) {
        throw new Error('API key Gemini belum di-set!\nOwner ketik: .sapikey1 [API_KEY]\nDapat key gratis di: aistudio.google.com/app/apikey')
    }

    const startIdx = _geminiKeyIdx < _validKeys.length ? _geminiKeyIdx : 0
    for (let attempt = 0; attempt < _validKeys.length; attempt++) {
        const keyIdx = (startIdx + attempt) % _validKeys.length
        const key = _validKeys[keyIdx]
        try {
            const _gRes = await axios.post(
                `https://generativelanguage.googleapis.com/v1beta/models/gemini-1.5-flash:generateContent?key=${key}`,
                { contents: [{ parts: [{ text: finalQuery }] }] },
                { timeout: 15000, headers: { 'Content-Type': 'application/json' } }
            )
            const _gText = _gRes.data?.candidates?.[0]?.content?.parts?.[0]?.text
            if (_gText && _gText.length > 2) {
                // Berhasil ‚Äî simpan key aktif
                if (_geminiKeyIdx !== keyIdx) { _geminiKeyIdx = keyIdx; _saveAiConfig() }
                return _gText
            }
            console.log(`[Gemini key#${keyIdx+1}] Response kosong, coba key berikutnya`)
        } catch(e) {
            const errCode = e.response?.status
            const errMsg = e.response?.data?.error?.message || e.message
            console.log(`[Gemini key#${keyIdx+1}] Error ${errCode}: ${errMsg}`)
            // Rotasi ke key berikutnya
            if (attempt < _validKeys.length - 1) {
                _geminiKeyIdx = (keyIdx + 1) % _validKeys.length
                _saveAiConfig()
            }
        }
    }

    // Semua Gemini key gagal ‚Äî fallback ke free API
    console.log('[AI] Semua Gemini key gagal, coba free API fallback...')

    // Pollinations AI ‚Äî paling stabil
    try {
        const _pRes = await axios.get(
            `https://text.pollinations.ai/${encodeURIComponent(finalQuery)}`,
            { timeout: 15000, headers: { 'User-Agent': 'Mozilla/5.0' } }
        )
        if (_pRes.data && typeof _pRes.data === 'string' && _pRes.data.length > 5) return _pRes.data.trim()
    } catch(e) {}

    // LuminAI Indonesia
    try {
        const _lRes = await axios.post('https://luminai.my.id/', { content: finalQuery, user: userId || 'user' }, { timeout: 12000 })
        if (_lRes.data?.result && _lRes.data.result.length > 2) return _lRes.data.result
    } catch(e) {}

    // Siputzx
    try {
        const _sRes = await axios.get(`https://api.siputzx.my.id/api/ai/meta-llama?prompt=${encodeURIComponent(finalQuery)}`, { timeout: 10000 })
        if (_sRes.data?.data && _sRes.data.data.length > 2) return _sRes.data.data
        if (_sRes.data?.result && _sRes.data.result.length > 2) return _sRes.data.result
    } catch(e) {}

    // Ryzendesu
    try {
        const _rRes = await axios.get(`https://api.ryzendesu.vip/api/ai/chatgpt?text=${encodeURIComponent(finalQuery)}`, { timeout: 10000 })
        if (_rRes.data?.response && _rRes.data.response.length > 2) return _rRes.data.response
    } catch(e) {}

    // DuckDuckGo AI Chat (GPT-4o-mini, no auth)
    try {
        const _ddgR1 = await axios.get('https://duckduckgo.com/duckchat/v1/status', { timeout: 5000, headers: { 'x-vqd-accept': '1' } })
        const _vqd = _ddgR1.headers['x-vqd-4']
        if (_vqd) {
            const _ddgR2 = await axios.post(
                'https://duckduckgo.com/duckchat/v1/chat',
                { model: 'gpt-4o-mini', messages: [{ role: 'user', content: finalQuery }] },
                { timeout: 15000, headers: { 'x-vqd-4': _vqd, 'Content-Type': 'application/json' } }
            )
            const _ddgLines = (_ddgR2.data?.toString() || '').split('\n').filter(l => l.startsWith('data:') && !l.includes('[DONE]'))
            const _ddgText = _ddgLines.map(l => { try { return JSON.parse(l.slice(5))?.message || '' } catch(e) { return '' } }).join('')
            if (_ddgText && _ddgText.length > 2) return _ddgText
        }
    } catch(e) {}

    // Itzpire
    try {
        const _itRes = await axios.get(`https://api.itzpire.com/ai/gpt?q=${encodeURIComponent(finalQuery)}`, { timeout: 10000 })
        if (_itRes.data?.answer && _itRes.data.answer.length > 2) return _itRes.data.answer
    } catch(e) {}

    throw new Error('AI tidak tersedia saat ini. Coba lagi nanti.')
}

function execPromise(cmd) {
    return new Promise((resolve, reject) => {
        exec(cmd, { maxBuffer: 1024 * 1024 * 200 }, (err, stdout) => { if (err) reject(err); else resolve(stdout) })
    })
}

function checkDlCooldown(pool, senderNumber) {
    const now = Date.now()
    if (!pool[senderNumber]) pool[senderNumber] = []
    pool[senderNumber] = pool[senderNumber].filter(t => now - t < 1200000)
    if (pool[senderNumber].length >= 3) { const tunggu = Math.ceil((1200000 - (now - pool[senderNumber][0])) / 60000); return { ok: false, tunggu } }
    pool[senderNumber].push(now)
    return { ok: true }
}

async function surfWeb(query) {
    try {
        const ddgResp = await axios.get(`https://api.duckduckgo.com/?q=${encodeURIComponent(query)}&format=json&no_html=1&skip_disambig=1`, { timeout: 8000, headers: { 'User-Agent': 'Mozilla/5.0' } })
        const ddg = ddgResp.data
        if (ddg.AbstractText && ddg.AbstractText.length > 50) return `üîç *${query}*\n\n${ddg.AbstractText}\n\nüìö Sumber: ${ddg.AbstractURL || 'DuckDuckGo'}`
        if (ddg.Answer && ddg.Answer.length > 10) return `üîç *${query}*\n\n${ddg.Answer}`
        if (ddg.RelatedTopics?.length > 0) { const topics = ddg.RelatedTopics.slice(0,3).map(t=>t.Text||'').filter(Boolean).join('\n\n'); if (topics.length > 30) return `üîç *${query}*\n\n${topics}` }
    } catch (e) {}
    try { const aiResult = await askAI(`Jawab pertanyaan berikut secara lengkap: ${query}`, 'surf'); return `üîç *${query}*\n\n${aiResult}\n\n‚ö° _Powered by Roma AI_` } catch (e) {}
    return `üîç *${query}*\n\n‚ùå Tidak dapat menemukan hasil.`
}

async function getCuaca(kota) {
    const resp = await axios.get(`https://wttr.in/${encodeURIComponent(kota)}?format=j1`, { timeout: 12000, headers: { 'User-Agent': 'curl/7.68.0' } })
    const w = resp.data; const cur = w.current_condition[0]; const area = w.nearest_area[0]
    const areaName = area.areaName[0].value; const country = area.country[0].value
    let forecastTxt = ''
    w.weather.slice(0,3).forEach(day => { forecastTxt += `‚ó¶ *${day.date}*: ${day.hourly[4]?.weatherDesc[0]?.value||'-'}, Max ${day.maxtempC}¬∞C / Min ${day.mintempC}¬∞C\n` })
    return `üå§Ô∏è *Cuaca ${areaName}, ${country}*\n‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ\nüå°Ô∏è *Suhu:* ${cur.temp_C}¬∞C (Terasa ${cur.FeelsLikeC}¬∞C)\n‚òÅÔ∏è *Kondisi:* ${cur.weatherDesc[0].value}\nüíß *Kelembaban:* ${cur.humidity}%\nüí® *Angin:* ${cur.windspeedKmph} km/h\nüëÅÔ∏è *Visibilitas:* ${cur.visibility} km\n\nüìÖ *Perkiraan 3 Hari:*\n${forecastTxt}`
}

// ‚ïê‚ïê Helper: download media dari quoted message ‚ïê‚ïê
async function downloadMedia(mediaObj, type) {
    const buffer = await downloadContentFromMessage(mediaObj, type)
    let bufferData = Buffer.from([])
    for await (const chunk of buffer) bufferData = Buffer.concat([bufferData, chunk])
    return bufferData
}

const readline = require('readline')

async function tanyaPilihan(pertanyaan) {
    const rl = readline.createInterface({ input: process.stdin, output: process.stdout })
    return new Promise(resolve => rl.question(pertanyaan, ans => { rl.close(); resolve(ans.trim()) }))
}



