    // SISTEM ANTI-BAN KOMPREHENSIF
    // ‚ïê‚ïê‚ïê‚ïê‚ïê‚ïê‚ïê‚ïê‚ïê‚ïê‚ïê‚ïê‚ïê‚ïê‚ïê‚ïê‚ïê‚ïê‚ïê‚ïê‚ïê‚ïê‚ïê‚ïê‚ïê‚ïê‚ïê‚ïê‚ïê‚ïê‚ïê‚ïê‚ïê‚ïê‚ïê‚ïê‚ïê‚ïê‚ïê‚ïê‚ïê‚ïê‚ïê‚ïê‚ïê‚ïê‚ïê‚ïê‚ïê‚ïê‚ïê‚ïê‚ïê‚ïê

    // Rate limiter ‚Äî track berapa pesan dikirim per menit
    const _msgCounter = { count: 0, resetAt: Date.now() + 60000 }
    const _checkRateLimit = () => {
        const now = Date.now()
        if (now > _msgCounter.resetAt) {
            _msgCounter.count = 0
            _msgCounter.resetAt = now + 60000
        }
        _msgCounter.count++
        // Kalau lebih dari 25 pesan/menit, tambah delay extra
        return _msgCounter.count > 25
    }

    // Delay dihapus ‚Äî bot super cepat
    const _humanDelay = () => 0
