    // ‚ïê‚ïê ANTI-SPAM REPLY COOLDOWN ‚ïê‚ïê
    // Mencegah bot kirim balasan ganda dalam waktu singkat untuk cmd yang sama dari user yang sama
    const _replyCooldown = new Map()  // key: senderNum + cmd, value: timestamp
    const _REPLY_CD_MS = 3000  // 3 detik cooldown per cmd per user

    function _checkReplyCooldown(senderNum, cmd) {
        const key = senderNum + '_' + cmd
        const last = _replyCooldown.get(key) || 0
        if (Date.now() - last < _REPLY_CD_MS) return false  // masih cooldown
        _replyCooldown.set(key, Date.now())
        // Bersihkan entry lama
        if (_replyCooldown.size > 1000) {
            const cutoff = Date.now() - _REPLY_CD_MS * 10
            for (const [k, v] of _replyCooldown.entries()) {
                if (v < cutoff) _replyCooldown.delete(k)
            }
        }
        return true
    }

