    const _injectChannelPromo = (msgContent) => {
        try {
            // Cek status promosi ‚Äî hanya parent owner yang bisa toggle via .promosi on/off
            // Child bot TIDAK inject promo (parent only)
            if (_IS_CHILD) return msgContent
            let _promoOn = true
            try { _promoOn = JSON.parse(require('fs').readFileSync('./promosi_status.json', 'utf8')).on !== false } catch(e) {}
            if (!_promoOn) return msgContent

            const _promoSuffix = '\n\nüì¢ _Yuk follow saluran kami! Ketik *.saluran* untuk info lebih lanjut._'
            // Inject ke field text
            if (typeof msgContent.text === 'string') {
                return { ...msgContent, text: msgContent.text + _promoSuffix }
            }
            // Inject ke caption (gambar/video/audio/dokumen)
            if (typeof msgContent.caption === 'string') {
                return { ...msgContent, caption: msgContent.caption + _promoSuffix }
            }
            // Kalau tidak ada text/caption (misal voice, dll), tambah sebagai teks terpisah tapi lewat field caption kalau bisa
            return msgContent
        } catch(e) { return msgContent }
    }

