    // ‚ïê‚ïê Game Helper Functions (di luar message handler agar tidak re-declare) ‚ïê‚ïê
    const updateXP = (num, amount) => {
        if (!fs.existsSync('./xp.json')) fs.writeFileSync('./xp.json', '{}')
        let xpData = JSON.parse(fs.readFileSync('./xp.json', 'utf8'))
        if (!xpData[num]) xpData[num] = { xp: 0, level: 1, totalCmds: 0 }
        xpData[num].xp = (xpData[num].xp || 0) + amount
        xpData[num].totalCmds = (xpData[num].totalCmds || 0) + 1
        const newLevel = Math.floor(xpData[num].xp / 100) + 1
        const oldLevel = xpData[num].level || 1
        xpData[num].level = newLevel
        fs.writeFileSync('./xp.json', JSON.stringify(xpData, null, 2))
        return { xp: xpData[num].xp, level: newLevel, leveledUp: newLevel > oldLevel, oldLevel }
    }

