            // ‚ïê‚ïê ANTI-DELETE: cache semua pesan non-bot & deteksi delete ‚ïê‚ïê
            if (isGroup && !msg.key.fromMe && msg.message && !msg.messageStubType) {
                const _mKey = msg.key.id
                const _mType = Object.keys(msg.message)[0]
                _msgCache.set(_mKey, { from, senderJid, senderNumber, type: _mType, message: msg.message, time: Date.now() })
                if (_msgCache.size > 500) {
                    const _oldest = [..._msgCache.entries()].sort((a,b)=>a[1].time-b[1].time)[0][0]
                    _msgCache.delete(_oldest)
                }
            }

