                        if (videoUploadDate && videoUploadDate.length === 8) {
                            const y = videoUploadDate.slice(0,4), m = videoUploadDate.slice(4,6), d = videoUploadDate.slice(6,8)
                            videoUploadDate = `${d}/${m}/${y}`
                        }
                        // Format angka views/likes
                        const fmtNum = n => { const num = parseInt(n); if(isNaN(num)) return ''; if(num>=1000000) return (num/1000000).toFixed(1)+'Jt'; if(num>=1000) return (num/1000).toFixed(1)+'Rb'; return num.toString() }
                        videoViews = fmtNum(videoViews)
                        videoLikes = fmtNum(videoLikes)
