                    if (videoChannel && videoChannel !== videoUploader) caption += `üì∫ *Channel:* ${videoChannel}\n`
                    if (videoUploadDate) caption += `üìÖ *Tanggal Upload:* ${videoUploadDate}\n`
                    if (videoDuration)   caption += `‚è±Ô∏è *Durasi:* ${videoDuration}\n`
                    if (videoResolution) caption += `üìê *Resolusi:* ${videoResolution}\n`
                    if (videoViews)      caption += `üëÅÔ∏è *Ditonton:* ${videoViews} kali\n`
                    if (videoLikes)      caption += `‚ù§Ô∏è *Likes:* ${videoLikes}\n`
                    caption += `üì¶ *Ukuran File:* ${fileSizeMB} MB\n`
                    caption += `‚ö° *Waktu Download:* ${((Date.now() - _startDL) / 1000).toFixed(1)}s\n`
