                // ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ
                if (lowerText === '.botgrup on' || lowerText === '.botgrup off') {
                    _botGrupEnabled = lowerText.includes('on')
                    let _bgCfg = {}
                    try { _bgCfg = JSON.parse(fs.readFileSync('./bot_config.json', 'utf8')) } catch(e) {}
                    _bgCfg.botGrupEnabled = _botGrupEnabled
                    fs.writeFileSync('./bot_config.json', JSON.stringify(_bgCfg, null, 2))
                    return await sendWithTyping(from, { text: _botGrupEnabled ? '‚úÖ *Bot Grup: ON*\nBot aktif di semua grup.' : 'üî¥ *Bot Grup: OFF*\nHanya owner/admin grup yang bisa pakai cmd.' }, { quoted: msg })
                }

                if (lowerText === '.botpc on' || lowerText === '.botpc off') {
                    _botPcEnabled = lowerText.includes('on')
                    let _bpCfg = {}
                    try { _bpCfg = JSON.parse(fs.readFileSync('./bot_config.json', 'utf8')) } catch(e) {}
                    _bpCfg.botPcEnabled = _botPcEnabled
                    fs.writeFileSync('./bot_config.json', JSON.stringify(_bpCfg, null, 2))
                    return await sendWithTyping(from, { text: _botPcEnabled ? '‚úÖ *Bot DM: ON*\nBot aktif menerima pesan japri.' : 'üî¥ *Bot DM: OFF*\nJapri ke bot tidak dilayani.' }, { quoted: msg })
                }

                // ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ
