                    const st2 = _sl_aw2[from] === 'on' ? 'üü¢ ON' : 'üî¥ OFF'
                    let txt2 = `üö´ *KATA TERLARANG*\n‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ\nStatus: ${st2} | Total: ${_bw2.length}\n\n`
                    txt2 += _bw2.length ? _bw2.map((w,i) => `${i+1}. ${w}`).join('\n') : 'Kosong. Tambah: .bad kata1, kata2'
                    return await sendWithTyping(from, { text: txt2 }, { quoted: msg })
