                    const newW2 = rawIn2.split(/[\n,]/).map(w => w.trim().toLowerCase()).filter(w => w.length > 0)
                    const added2 = newW2.filter(w => !_bw2.includes(w))
                    const skipped2 = newW2.length - added2.length
