                if (lowerText === '.antidelete on' || lowerText === '.antidelete off') { const _st=lowerText.includes('on')?'on':'off'; saveSecCfg(from,{antiDelete:_st}); return await sendWithTyping(from,{text:`üóëÔ∏è *Anti-Delete: ${_st.toUpperCase()}*\nPesan yang dihapus member ${_st==='on'?'akan dikirim ulang bot':'tidak di-resend'}.`},{quoted:msg}) }
                if ((lowerText === '.anticaps on' || lowerText === '.anticaps off')) { saveSecCfg(from, { antiCaps: lowerText.includes('on')?'on':'off' }); return await sendWithTyping(from, { text: `üî° *Anti-CAPS: ${lowerText.includes('on')?'ON':'OFF'}*` }, { quoted: msg }) }
