                if ((lowerText === '.antijl on' || lowerText === '.antijl off')) { saveSecCfg(from, { antiJl: lowerText.includes('on')?'on':'off' }); return await sendWithTyping(from, { text: `üö™ *Anti Join-Leave: ${lowerText.includes('on')?'ON':'OFF'}*` }, { quoted: msg }) }
