                if ((lowerText === '.captcha on' || lowerText === '.captcha off')) { saveSecCfg(from, { captcha: lowerText.includes('on')?'on':'off' }); return await sendWithTyping(from, { text: `üîê *Captcha: ${lowerText.includes('on')?'ON':'OFF'}*` }, { quoted: msg }) }
                if ((lowerText === '.antihoaks on' || lowerText === '.antihoaks off')) { saveSecCfg(from, { antiHoaks: lowerText.includes('on')?'on':'off' }); return await sendWithTyping(from, { text: `üì∞ *Anti-Hoaks: ${lowerText.includes('on')?'ON':'OFF'}*` }, { quoted: msg }) }
