                    if (!_mt2) return await sendWithTyping(from, { text: '‚öÝÔ∏è *Format .muted:*\nReply pesan member + .muted [menit]\nAtau: .muted [menit] @mention\nContoh: .muted 30 @user\nContoh: .muted 0 (permanen)' }, { quoted: msg })
                    const _ma2 = fullText.trim().split(' ')
