                    await sendWithTyping(from, { text: `üòÇ *JOKES OF THE DAY*\n‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ\n\n‚ùì ${setup}\n\nüí¨ ${punchline}\n\nüòÇ _Jangan ketawa sendirian!_` }, { quoted: msg })
