                    const tips = key ? healthTips[key] : ['Rutin olahraga 30 menit/hari üèÉ','Minum 8 gelas air putih üíß','Tidur cukup 7-9 jam ‚è∞','Konsumsi makanan bergizi ü•ó','Kelola stres dengan baik üòå']
                    let txt = `üíä *TIPS SEHAT: ${topik.toUpperCase()}*\n‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ\n`
                    tips.forEach((t, i) => txt += `${i+1}. ${t}\n`)
                    txt += `\n‚öÝÔ∏è _Ini bukan pengganti saran dokter profesional._`
