                    await sendWithTyping(from, { text: `‚ú® *VARIASI NAMA: ${nama.toUpperCase()}*\n‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ\n${result}` }, { quoted: msg })
