                        await sendWithTyping(from, { video: ob, caption: `COLOR GRADE: ${style.toUpperCase()}\nWaktu: ${((Date.now()-_sPV3)/1000).toFixed(2)}s`, mimetype: 'video/mp4' }, { quoted: msg })
