                        const ob = fs.readFileSync(op)
                        if (ob.length/(1024*1024) > 60) { try{fs.unlinkSync(ip);fs.unlinkSync(op)}catch(e){}; return await sendWithTyping(from, { text: '‚ùå Hasil terlalu besar.' }, { quoted: msg }) }
                        await sendWithTyping(from, { video: ob, caption: `DENOISE VIDEO PREMIUM\nWaktu: ${((Date.now()-_sPV4)/1000).toFixed(2)}s`, mimetype: 'video/mp4' }, { quoted: msg })
